mapper.insert:
INSERT INTO amz_fba_shipment (
    sid, username, shipment_id, shipment_name,shipment_status, msku, sku,
    quantity_shipped, init_quantity_shipped, quantity_received, quantity_shipped_local, declared_diff,
    gmt_create, gmt_modified, working_time, shipped_time, receiving_time, closed_time
) VALUES (
    #{sid}, #{username}, #{shipmentId}, #{shipmentName},#{shipmentStatus}, #{msku}, #{sku},
    #{quantityShipped}, #{initQuantityShipped}, #{quantityReceived}, #{quantityShippedLocal},
    #{quantityShipped} - #{quantityReceived},
    #{gmtCreate}, #{gmtModified}, #{workingTime}, #{shippedTime}, #{receivingTime}, #{closedTime}
)

mapper.select:
SELECT s.*, sl.store_name, COALESCE(m.remark, '') AS remark, COALESCE(m.confirmed, 0) AS confirmed
FROM amz_fba_shipment s
LEFT JOIN shop_list sl ON CAST(s.sid AS CHAR) COLLATE utf8mb4_unicode_ci = sl.sid AND sl.platform_code = '10001'
LEFT JOIN amz_fba_shipment_mark m ON s.msku = m.msku AND s.shipment_id = m.shipment_id

     and COALESCE(m.confirmed, 0) = #{params.confirmed} 
    and s.username IS NOT NULL and s.username != ''
     and sl.store_name like concat('%', #{params.storeName}, '%') 
     and s.shipment_id like concat('%', #{params.shipmentId}, '%') 
     and s.sku like concat('%', #{params.sku}, '%') 
     and s.msku like concat('%', #{params.msku}, '%') 
     and s.username like concat('%', #{params.username}, '%') 
     and s.shipment_status = #{params.shipmentStatus} 
     and s.gmt_create >= #{params.gmtCreateStart} 
     and s.gmt_create <= #{params.gmtCreateEnd} 
     and s.gmt_modified >= #{params.gmtModifiedStart} 
     and s.gmt_modified <= #{params.gmtModifiedEnd} 


         and sid between #{params.sid_val} and #{params.sid_val2} 
         and sid is null 
         and sid is not null 
         and sid ${params.sid_op} #{params.sid_val} 


         and quantity_shipped between #{params.quantity_shipped_val} and #{params.quantity_shipped_val2} 
         and quantity_shipped is null 
         and quantity_shipped is not null 
         and quantity_shipped ${params.quantity_shipped_op} #{params.quantity_shipped_val} 


         and quantity_received between #{params.quantity_received_val} and #{params.quantity_received_val2} 
         and quantity_received is null 
         and quantity_received is not null 
         and quantity_received ${params.quantity_received_op} #{params.quantity_received_val} 


         and quantity_shipped_local between #{params.quantity_shipped_local_val} and #{params.quantity_shipped_local_val2} 
         and quantity_shipped_local is null 
         and quantity_shipped_local is not null 
         and quantity_shipped_local ${params.quantity_shipped_local_op} #{params.quantity_shipped_local_val} 


         and init_quantity_shipped between #{params.init_quantity_shipped_val} and #{params.init_quantity_shipped_val2} 
         and init_quantity_shipped is null 
         and init_quantity_shipped is not null 
         and init_quantity_shipped ${params.init_quantity_shipped_op} #{params.init_quantity_shipped_val} 


         and declared_diff between #{params.declared_diff_val} and #{params.declared_diff_val2} 
         and declared_diff is null 
         and declared_diff is not null 
         and declared_diff ${params.declared_diff_op} #{params.declared_diff_val} 



    order by s.shipment_id
    order by s.sku
    order by s.quantity_shipped
    order by s.quantity_received
    order by s.declared_diff
    order by s.gmt_create
    order by s.gmt_create desc, s.shipment_id, s.sku


    asc
    desc
